'use client';

import { useState, useEffect } from 'react';

export default function AdminPanel() {
    const [isAuthenticated, setIsAuthenticated] = useState(false);
    const [user, setUser] = useState('');
    const [pass, setPass] = useState('');

    const [priceAmount, setPriceAmount] = useState('49.90');
    const [geminiApiKey, setGeminiApiKey] = useState('');
    const [mercadoPagoToken, setMercadoPagoToken] = useState('');
    const [logs, setLogs] = useState([]);

    const [loading, setLoading] = useState(false);
    const [saved, setSaved] = useState(false);

    useEffect(() => {
        if (isAuthenticated) {
            // Basic fetch
            fetch('/api/admin/config')
                .then(res => res.json())
                .then(data => {
                    if (data.config) {
                        setPriceAmount(data.config.priceAmount.toString());
                        setGeminiApiKey(data.config.geminiApiKey || '');
                        setMercadoPagoToken(data.config.mercadoPagoToken || '');
                    }
                    if (data.logs) {
                        setLogs(data.logs);
                    }
                });
        }
    }, [isAuthenticated]);

    const handleLogin = (e: React.FormEvent) => {
        e.preventDefault();
        const normalizedUser = user.trim().toLowerCase();
        const normalizedPass = pass.trim();

        if (normalizedUser === 'admin' && normalizedPass === 'admin') {
            setIsAuthenticated(true);
        } else {
            alert('Credenciais erradas!');
        }
    };

    const saveSettings = async () => {
        setLoading(true);
        try {
            await fetch('/api/admin/config', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    priceAmount: parseFloat(priceAmount),
                    geminiApiKey,
                    mercadoPagoToken
                })
            });
            setSaved(true);
            setTimeout(() => setSaved(false), 3000);
        } catch (e) {
            alert('Erro ao salvar config.');
        } finally {
            setLoading(false);
        }
    };

    if (!isAuthenticated) return (
        <div className="flex-center" style={{ minHeight: '100vh', background: '#f8fafc' }}>
            <form onSubmit={handleLogin} className="glass-card" style={{ display: 'flex', flexDirection: 'column', gap: 16, width: 400 }}>
                <h2>Admin Login</h2>
                <input className="input-field" placeholder="Usuário (admin)" value={user} onChange={e => setUser(e.target.value)} />
                <input className="input-field" type="password" placeholder="Senha (admin)" value={pass} onChange={e => setPass(e.target.value)} />
                <button type="submit" className="btn btn-primary">Entrar</button>
            </form>
        </div>
    );

    return (
        <div style={{ backgroundColor: '#f0f5ff', minHeight: '100vh', padding: 48 }}>
            <div className="container" style={{ maxWidth: 1000 }}>
                <h1 style={{ marginBottom: 40 }}>Painel Administrativo</h1>

                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 32 }}>
                    {/* Configs */}
                    <div className="glass-card">
                        <h3>Configurações do Sistema</h3>

                        <div style={{ display: 'flex', flexDirection: 'column', gap: 16, marginTop: 24 }}>
                            <label>
                                <span style={{ fontWeight: 600, display: 'block', marginBottom: 4 }}>Preço (BRL)</span>
                                <input type="number" step="0.01" className="input-field" value={priceAmount} onChange={e => setPriceAmount(e.target.value)} />
                            </label>

                            <label>
                                <span style={{ fontWeight: 600, display: 'block', marginBottom: 4 }}>Gemini API Key (Para Pipeline)</span>
                                <input type="text" className="input-field" value={geminiApiKey} onChange={e => setGeminiApiKey(e.target.value)} placeholder="AIzaSy..." />
                            </label>

                            <label>
                                <span style={{ fontWeight: 600, display: 'block', marginBottom: 4 }}>Mercado Pago Access Token</span>
                                <input type="password" className="input-field" value={mercadoPagoToken} onChange={e => setMercadoPagoToken(e.target.value)} placeholder="APP_USR-..." />
                            </label>

                            <button className="btn btn-primary" onClick={saveSettings} disabled={loading} style={{ marginTop: 24 }}>
                                {loading ? 'Salvando...' : 'Salvar Alterações'}
                            </button>
                            {saved && <span style={{ color: 'green', fontSize: '0.875rem' }}>Configurações salvas atualizadas com sucesso!</span>}
                        </div>
                    </div>

                    {/* Logs */}
                    <div className="glass-card">
                        <h3>Logs de Geração (Últimos 24h)</h3>
                        <div style={{ overflowY: 'auto', maxHeight: 450, marginTop: 24 }}>
                            {logs.length === 0 ? <p>Nenhum log encontrado.</p> : (
                                <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.875rem' }}>
                                    <thead>
                                        <tr style={{ textAlign: 'left', borderBottom: '1px solid #e2e8f0' }}>
                                            <th style={{ padding: '8px 0' }}>Empresa</th>
                                            <th>Status</th>
                                            <th>Data</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {logs.map((log: any) => (
                                            <tr key={log.id} style={{ borderBottom: '1px solid #f1f5f9' }}>
                                                <td style={{ padding: '12px 0' }}>{log.companyName}</td>
                                                <td style={{ color: log.paymentStatus === 'APPROVED' ? 'green' : 'orange' }}>
                                                    {log.paymentStatus}
                                                </td>
                                                <td>{new Date(log.createdAt).toLocaleDateString()}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            )}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}
